const { ApolloServer, gql } = require('apollo-server');
const { validateInvoiceId, getInvoiceById } = require('./invoiceService');

const typeDefs = gql`
  type Invoice {
    id: ID!
    amount: Float!
    date: String!
    customerName: String!
  }

  type Query {
    invoice(id: ID!): Invoice
  }
`;

const resolvers = {
  Query: {
    invoice: async (_, { id }, context) => {
      // Validate the invoice ID
      if (!validateInvoiceId(id)) {
        throw new Error('Invalid invoice ID');
      }

      // Fetch the invoice details securely
      const invoice = await getInvoiceById(id);

      if (!invoice) {
        throw new Error('Invoice not found');
      }

      return invoice;
    }
  }
};

const server = new ApolloServer({
  typeDefs,
  resolvers,
  context: ({ req }) => {
    // Assuming authentication middleware has already set user in context
    const user = req.user;
    if (!user) {
      throw new Error('Unauthorized');
    }
    return { user };
  },
  formatError: (err) => {
    // Avoid leaking sensitive error details
    return new Error('Internal server error');
  }
});

server.listen().then(({ url }) => {
  console.log(`🚀 Server ready at ${url}`);
});